  "code": "def prod_signs(arr):
    """
    Computes the sum of magnitudes and multiplies it by the sign product, where signs are defined as 1, -1, or 0. Returns None if the input list is empty.

    Example:
    >>> prod_signs([1, 2, 2, -4]) == -9
    >>> prod_signs([0, 1]) == 0
    >>> prod_signs([]) == None
    """
    if not arr:
        return None

    sum_of_magnitudes = sum(abs(x) for x in arr)
    sign_product = 1

    for num in arr:
        if num > 0:
            sign_product *= 1
        elif num < 0:
            sign_product *= -1
        else:
            return 0

    return sum_of_magnitudes * sign_product",
